import { GoogleGenAI, Tool } from "@google/genai";

const modelId = "gemini-2.5-flash";

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  grounding?: any;
}

export const sendMessageToGemini = async (
  message: string,
  location?: { latitude: number; longitude: number }
): Promise<{ text: string; grounding?: any }> => {
  try {
    // Initialize inside the function to avoid top-level fetch errors
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const tools: Tool[] = [{ googleMaps: {} }];

    // Construct tool config with location if available
    const toolConfig = location ? {
      retrievalConfig: {
        latLng: {
          latitude: location.latitude,
          longitude: location.longitude
        }
      }
    } : undefined;

    const systemInstruction = `Vous êtes l'assistant virtuel de LAMUKA, un collectif engagé au Congo Brazzaville.

    BASE DE CONNAISSANCES DU SITE WEB :

    1. ORGANISATION & CONTACT
       - Nom : LAMUKA.
       - Mission : Lutte contre les VBG, inclusion femmes handicapées, santé sexuelle, autonomisation.
       - Siège : 20 rue Kimpouanza, Avenue Mayama, Mfilou, Brazzaville.
       - Téléphone : +242 06 920 60 58 / +242 06 769 61 57.
       - Email : collectiflamuka2025@gmail.com.

    2. NOS SERVICES / ACTIONS
       - Écoute : Ligne d'écoute et groupes de parole pour victimes.
       - Juridique : Accompagnement gratuit (Avocats partenaires) pour démarches judiciaires. Permanence le mercredi matin.
       - Santé : Cliniques mobiles, formation du personnel médical à l'accueil inclusif.
       - Autonomisation : Formation numérique "Digital Pour Toutes", ateliers artisanat.

    3. ACTUALITÉS & BLOG (À CITER SI PERTINENT)
       - Campagne "Brisons le Silence" : Distribution de kits d'alerte (sifflets) à 200 femmes à Mfilou.
       - Témoignage : Sophie, couturière paraplégique à Pointe-Noire (Atelier "Mains de Fée"), emploie des femmes sourdes-muettes.
       - Droit : L'article 15 punit les abus sur personnes vulnérables. Les entreprises (>50 employés) ont des quotas d'embauche.
       - Partenariat Mfilou : Soins d'urgence gratuits pour victimes VBG dans 3 centres de santé pilotes.
       - Formation Santé : 20 sages-femmes formées à Brazzaville sur les soins inclusifs.

    RÈGLES DE RÉPONSE :
    1. STYLE : Réponses COURTES, PRÉCISES et DIRECTES. Pas de phrases de politesse interminables.
    2. STRUCTURE : Utilisez impérativement des listes à puces pour énumérer.
    3. MISE EN FORME : Mettez les mots-clés importants (noms, lieux, numéros) en **GRAS** (ex: **20 rue Kimpouanza**).
    4. MAPS : Si l'utilisateur cherche un lieu (hôpital, centre, pharmacie), utilisez l'outil googleMaps et résumez les résultats.
    5. URGENCE : Pour les cas graves, renvoyez vers les numéros d'urgence locaux.
    `;

    const response = await ai.models.generateContent({
      model: modelId,
      contents: message,
      config: {
        tools,
        toolConfig,
        systemInstruction,
        temperature: 0.5,
      },
    });

    const candidate = response.candidates?.[0];
    const text = candidate?.content?.parts?.map(p => p.text).join('') || "Je suis désolé, je n'ai pas pu générer de réponse.";

    const grounding = candidate?.groundingMetadata?.groundingChunks;

    return { text, grounding };
  } catch (error) {
    console.error("Gemini API Error:", error);
    return { text: "Désolé, une erreur est survenue lors de la connexion à l'assistant. Veuillez réessayer plus tard." };
  }
};
